This sample shows how to call UploadSessionFileAsync and parse the result.

Uri endpoint = new Uri("<endpoint>");
TokenCredential credential = new DefaultAzureCredential();
AgentSessionFiles client = new AIProjectClient(endpoint, credential).GetAgentSessionFilesClient(apiVersion: "virtual-public-preview");

using RequestContent content = RequestContent.Create(new object());
Response response = await client.UploadSessionFileAsync("<agent_name>", "<session_id>", "<path>", content);

JsonElement result = JsonDocument.Parse(response.ContentStream).RootElement;
Console.WriteLine(result.GetProperty("path").ToString());
Console.WriteLine(result.GetProperty("bytes_written").ToString());

