This sample shows how to call GetSessionFilesAsync and parse the result.

Uri endpoint = new Uri("<endpoint>");
TokenCredential credential = new DefaultAzureCredential();
AgentSessionFiles client = new AIProjectClient(endpoint, credential).GetAgentSessionFilesClient(apiVersion: "virtual-public-preview");

Response response = await client.GetSessionFilesAsync("<agent_name>", "<session_id>", "<path>", null, null);

JsonElement result = JsonDocument.Parse(response.ContentStream).RootElement;
Console.WriteLine(result.GetProperty("path").ToString());
Console.WriteLine(result.GetProperty("entries")[0].GetProperty("name").ToString());
Console.WriteLine(result.GetProperty("entries")[0].GetProperty("size").ToString());
Console.WriteLine(result.GetProperty("entries")[0].GetProperty("is_directory").ToString());
Console.WriteLine(result.GetProperty("entries")[0].GetProperty("modified_time").ToString());

